import { d as db, v as visas } from '../homepage/GET-Bfuc7iwF.js';

async function handler(req, res) {
  try {
    const {
      visaId,
      title,
      description,
      countries,
      processingTime,
      validity,
      stayDuration,
      price,
      image,
      requiredDocuments,
      applicationProcess,
      faqs
    } = req.body;
    if (!visaId || !title || !description || !countries || !processingTime || !validity || !stayDuration || !price || !image) {
      return res.status(400).json({
        success: false,
        error: "Missing required fields"
      });
    }
    const result = await db.insert(visas).values({
      visaId,
      title,
      description,
      countries,
      processingTime,
      validity,
      stayDuration,
      price,
      image,
      requiredDocuments: requiredDocuments || [],
      applicationProcess: applicationProcess || [],
      faqs: faqs || []
    });
    res.status(201).json({
      success: true,
      message: "Visa created successfully",
      visaId: result[0].insertId
    });
  } catch (error) {
    console.error("Error creating visa:", error);
    res.status(500).json({
      success: false,
      error: "Failed to create visa",
      message: String(error)
    });
  }
}

export { handler as h };
