import { d as db, a as homepageContent } from './GET-Bfuc7iwF.js';
import { eq } from 'drizzle-orm';

async function handler(req, res) {
  try {
    const content = req.body;
    const existing = await db.select().from(homepageContent).where(eq(homepageContent.sectionId, "main")).limit(1);
    if (existing.length > 0) {
      await db.update(homepageContent).set({ content }).where(eq(homepageContent.sectionId, "main"));
    } else {
      await db.insert(homepageContent).values({
        sectionId: "main",
        content
      });
    }
    res.json({ success: true, message: "Homepage content updated successfully" });
  } catch (error) {
    console.error("Error updating homepage content:", error);
    res.status(500).json({
      success: false,
      error: "Failed to update homepage content",
      message: String(error)
    });
  }
}

export { handler as h };
