import { d as db, p as packages } from '../../homepage/GET-Bfuc7iwF.js';

async function handler(req, res) {
  try {
    const {
      packageId,
      name,
      location,
      price,
      rating,
      duration,
      groupSize,
      description,
      image,
      highlights,
      itinerary,
      included,
      notIncluded
    } = req.body;
    if (!packageId || !name || !location || !price || !rating || !duration || !groupSize || !description || !image) {
      return res.status(400).json({
        success: false,
        error: "Missing required fields"
      });
    }
    const result = await db.insert(packages).values({
      packageId,
      name,
      location,
      price: parseInt(price),
      rating: rating.toString(),
      duration,
      groupSize,
      description,
      image,
      highlights: highlights || [],
      itinerary: itinerary || [],
      included: included || [],
      notIncluded: notIncluded || []
    });
    res.status(201).json({
      success: true,
      message: "Package created successfully",
      packageId: result[0].insertId
    });
  } catch (error) {
    console.error("Error creating package:", error);
    res.status(500).json({
      success: false,
      error: "Failed to create package",
      message: String(error)
    });
  }
}

export { handler as h };
