import { d as db, s as siteSettings } from '../homepage/GET-Bfuc7iwF.js';
import { eq } from 'drizzle-orm';

async function handler(req, res) {
  try {
    const settings = req.body;
    const existing = await db.select().from(siteSettings).where(eq(siteSettings.settingKey, "site_config")).limit(1);
    if (existing.length > 0) {
      await db.update(siteSettings).set({
        settingValue: JSON.stringify(settings)
      }).where(eq(siteSettings.settingKey, "site_config"));
    } else {
      await db.insert(siteSettings).values({
        settingKey: "site_config",
        settingValue: JSON.stringify(settings),
        settingType: "json"
      });
    }
    res.json({ success: true, message: "Site settings updated successfully" });
  } catch (error) {
    console.error("Error updating site settings:", error);
    res.status(500).json({
      success: false,
      error: "Failed to update site settings",
      message: String(error)
    });
  }
}

export { handler as h };
